SELECT DISTINCT s.*
FROM product_spu_table s
LEFT JOIN product_sku_table sku ON s.product_spu_id = sku.product_spu_id


        AND s.product_spu_code = #{reqVO.productSpuCode}


        AND s.product_spu_name LIKE CONCAT('%', #{reqVO.productSpuName}, '%')


        AND s.product_brand = #{reqVO.productBrand}


        AND s.category_id = #{reqVO.categoryId}


        AND s.product_origin LIKE CONCAT('%', #{reqVO.productOrigin}, '%')


        AND s.product_manufacturer LIKE CONCAT('%', #{reqVO.productManufacturer}, '%')


        AND s.product_spec_template LIKE CONCAT('%', #{reqVO.productSpecTemplate}, '%')


        AND s.product_spu_status = #{reqVO.productSpuStatus}


        AND s.create_time BETWEEN #{reqVO.createTime[0]} AND #{reqVO.createTime[1]}


        AND sku.product_sku_code LIKE CONCAT('%', #{reqVO.productSkuCode}, '%')


        AND sku.product_sku_name LIKE CONCAT('%', #{reqVO.productSkuName}, '%')


ORDER BY s.product_spu_id DESC
